sys_script_include.script:
var TableProviderContractValidator = Class.create();
TableProviderContractValidator.prototype = {
    initialize: function () {},

    validate: function (widgetHelper, logger) {
        var requiredMethods = [
            "canCreate",
            "canFilter",
            "canSavePreferences",
            "canConfigureColumns",
            "getAllAvailableColumns",
            "getAppliedFiltersInfoMessage",
            "getChoiceValues",
            "getDefaultColumns",
            "getDetailViewPage",
            "getFilterFields",
            "getIdField",
            "getRowClickAction",
            "getCellContent",
            "getOrderBy",
            "getOrderDirection",
            "getPageTitle",
            "getTableColumns",
            "getTableData",
            "getTableLimit",
            "getTotalRecords",
            "saveUserPreference",
            "showAppliedFilters",
            "showTableMetadata",
        ];

        var missingMethods = requiredMethods.filter(function (methodName) {
            return typeof widgetHelper[methodName] !== "function";
        });

        if (missingMethods.length > 0) {
            if (logger && typeof logger.error === "function") {
                logger.error({
                    message: "Provider is missing required methods",
                    missingMethods: missingMethods,
                });
            }
            return false;
        }

        return true;
    },

    type: "TableProviderContractValidator",
};
